import 'package:flutter/material.dart';
import '../services/app_store.dart';
import '../widgets/common.dart';
class InsightsScreen extends StatelessWidget{const InsightsScreen({super.key,required this.store});final AppStore store;@override Widget build(BuildContext context){final total=store.data.entries.fold(0,(a,b)=>a+b.durationSeconds);return Scaffold(appBar:AppBar(title:const Text('Статистика')),body:ListView(padding:const EdgeInsets.fromLTRB(16,12,16,100),children:[MetricCard(icon:Icons.timer_outlined,label:'Всего учтено',value:formatDuration(total)),const SizedBox(height:10),MetricCard(icon:Icons.auto_stories_outlined,label:'Заметок',value:'${store.data.notes.length}'),const SizedBox(height:10),MetricCard(icon:Icons.done_all_rounded,label:'Завершено задач',value:'${store.data.tasks.where((e)=>e.status=='done').length}'),const SizedBox(height:22),const SectionTitle('По проектам'),...store.data.projects.map((p){final sec=store.data.entries.where((e)=>e.projectId==p.id).fold(0,(a,b)=>a+b.durationSeconds);final ratio=total==0?0.0:sec/total;return Card(child:Padding(padding:const EdgeInsets.all(16),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Row(children:[Text(p.emoji),const SizedBox(width:8),Expanded(child:Text(p.title,style:const TextStyle(fontWeight:FontWeight.w600))),Text(formatDuration(sec))]),const SizedBox(height:10),LinearProgressIndicator(value:ratio,borderRadius:BorderRadius.circular(99))])));})]));}}
